dslRule:
"ModuleDeclaration API (setModule) is only available from Java 9 onwards, so usage in older Java versions may lead to compilation or runtime errors":
$compilationUnit.setModule($moduleDeclaration) :: sourceVersionLE(8)
;;

dslRuleAfterChange:
// Hypothetical DSL rule (requires new DSL features)
@id: generify.arraylist.from.context
new java.util.ArrayList() :: inferredTypeArgumentForDeclaration($var, $T)
=> new java.util.ArrayList<$T>()
;;

// Hypothetical DSL rule (requires new DSL features)
@id: generify.list.return.type
$returnType $name($params$) :: isRawType($returnType) && inferredTypeArgumentForMethod($name, $T)
=> $returnType<$T> $name($params$)
;;

/* Hypothetical DSL rule after language extension */

// Add generic type argument to ArrayList constructor based on declaration
new java.util.ArrayList() :: parentMatches("$type $var = new java.util.ArrayList()")
                         :: $var instanceof java.util.List
                         :: $var.hasGenericType($genericType)
=> new java.util.ArrayList<$genericType>()
;;

// Add generic type argument to method return type
$returnType $name($params$) :: $returnType instanceof java.util.List
                           :: methodDeclaresTypeParam($typeParam)
=> $returnType<$typeParam> $name($params$)
;;

/* Note: The above 'dslRuleAfterChange' uses advanced hypothetical features (e.g., `parentMatches` combined with type inference for generic arguments, and `methodDeclaresTypeParam`) that are not part of the current DSL and illustrate the kind of extensions needed. */

// Add module name resolution to key generation if a module is present (Java 9+)
// This rule only covers the ternary expression modification from the commit.
// The addition of an 'else if (element instanceof BinaryModule)' block is NOT supported by the current DSL.

$resolver.hasTypeName() ? $resolver.getKey().toCharArray() : org.eclipse.jdt.internal.compiler.util.CharOperation.concatWith($resolver.compoundName(), '.') :: sourceVersionGE(9)
=> $resolver.hasTypeName() ? $resolver.getKey().toCharArray() : $resolver.hasModuleName() ? $resolver.moduleName() : org.eclipse.jdt.internal.compiler.util.CharOperation.concatWith($resolver.compoundName(), '.')
;;
